  9→import { LexicalComposer } from '@lexical/react/LexicalComposer';
 10→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
 11→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 12→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
 13→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 14→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
 15→import ImageNode from '../../HomePage/Editor/nodes/ImageNode';
 16→
 17→import './ChapterReader.css';
 18→
 19→const readerTheme = {
 20→    paragraph: 'editor-paragraph',
 21→    heading: {
 22→        h1: 'editor-heading-h1',
 23→        h2: 'editor-heading-h2',
 24→        h3: 'editor-heading-h3',
 25→    },
 26→    quote: 'editor-quote',
 27→    text: {
 28→        bold: 'editor-text-bold',
 29→        italic: 'editor-text-italic',
 30→        underline: 'editor-text-underline',
 31→    },
 32→};
 33→
 34→const ReaderContent = ({ chapter }) => {
 35→    const [editor] = useLexicalComposerContext();
 36→
 37→    useEffect(() => {
 38→        if (chapter?.content && editor) {
 39→            try {
 40→                const content = typeof chapter.content === 'string'
 41→                    ? chapter.content
 42→                    : JSON.stringify(chapter.content);
 43→                const state = editor.parseEditorState(content);
 44→                editor.setEditorState(state);
 45→            } catch (err) {
 46→                console.error('Failed to load chapter content:', err);
 47→            }
 48→            editor.setEditable(false);
 49→        }
 50→    }, [chapter?.id, editor]);
 51→
 52→    return (
 53→        <RichTextPlugin
 54→            contentEditable={<ContentEditable className="chapter-reader-content" />}
 55→            ErrorBoundary={LexicalErrorBoundary}
 56→        />
 57→    );
 58→};
 59→
 60→const ChapterReader = () => {
 61→    const { storyId, chapterId } = useParams();
 62→    const navigate = useNavigate();
 63→    const { session } = useAuth();
 64→    const token = session?.access_token;
 65→
 66→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 67→    const progressTimerRef = useRef(null);
 68→    const scrollRef = useRef(0);
 69→
 70→    // Save reading progress debounced on scroll
 71→    const saveProgress = useCallback(() => {
 72→        if (!token || !storyId || !chapterId) return;
 73→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 74→    }, [token, storyId, chapterId]);
 75→
 76→    useEffect(() => {
 77→        const handleScroll = () => {
 78→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
 79→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
 80→            scrollRef.current = docHeight > 0 ? Math.min(scrollTop / docHeight, 1) : 0;
 81→
 82→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 83→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 84→        };
 85→
 86→        window.addEventListener('scroll', handleScroll, { passive: true });
 87→        return () => {
 88→            window.removeEventListener('scroll', handleScroll);
 89→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 90→            // Save on unmount
 91→            saveProgress();
 92→        };
 93→    }, [saveProgress]);
 94→
 95→    // Scroll progress bar
 96→    useEffect(() => {
 97→        const bar = document.getElementById('chapter-progress-bar');
 98→        if (!bar) return;
 99→
100→        const updateBar = () => {
101→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
102→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
103→            const pct = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
104→            bar.style.width = `${Math.min(pct, 100)}%`;
105→        };
106→
107→        window.addEventListener('scroll', updateBar, { passive: true });
108→        return () => window.removeEventListener('scroll', updateBar);
109→    }, []);
110→
111→    const editorConfig = {
112→        namespace: 'ChapterReader',
113→        theme: readerTheme,
114→        nodes: [ImageNode, HeadingNode, QuoteNode],
115→        editable: false,
116→        onError(error) { console.error('Lexical error:', error); },
117→    };
118→
119→    if (isLoading) {
120→        return (
121→            <div className="chapter-reader">
122→                <div className="chapter-reader-loading">
123→                    <BeatLoader size={10} color="var(--text-muted)" />
124→                </div>
125→            </div>
126→        );
127→    }
128→
129→    if (!chapter) {
130→        return (
131→            <div className="chapter-reader">
132→                <p className="chapter-reader-error">Chapter not found.</p>
133→            </div>
134→        );
135→    }
136→
137→    const prevCh = chapter.prev_chapter;
138→    const nextCh = chapter.next_chapter;
139→
140→    return (
141→        <motion.div
142→            className="chapter-reader"
143→            initial={{ opacity: 0 }}
144→            animate={{ opacity: 1 }}
145→            transition={{ duration: 0.2 }}
146→        >
147→            {/* Progress bar */}
148→            <div className="chapter-progress-track">
149→                <div id="chapter-progress-bar" className="chapter-progress-fill" />
150→            </div>
151→
152→            {/* Header */}
153→            <div className="chapter-reader-header">
154→                <button
155→                    className="chapter-reader-back"
156→                    onClick={() => navigate(`/home/stories/${storyId}`)}
157→                >
158→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
159→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
160→                    </svg>
161→                </button>
162→                <div className="chapter-reader-header-info">
163→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
164→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
165→                </div>
166→            </div>
167→
168→            {/* Content */}
169→            <div className="chapter-reader-body">
170→                <LexicalComposer initialConfig={editorConfig}>
171→                    <ReaderContent chapter={chapter} />
172→                </LexicalComposer>
173→            </div>
174→
175→            {/* Navigation */}
176→            <div className="chapter-reader-nav">
177→                {prevCh ? (
178→                    <button
179→                        className="chapter-nav-btn chapter-nav-prev"
180→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
181→                    >
182→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
183→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
184→                        </svg>
185→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
186→                    </button>
187→                ) : <div />}
188→                {nextCh ? (
189→                    <button
190→                        className="chapter-nav-btn chapter-nav-next"
191→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
192→                    >
193→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
194→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
195→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
196→                        </svg>
197→                    </button>
198→                ) : <div />}
199→            </div>
200→        </motion.div>
201→    );
202→};
203→
204→export default ChapterReader;
