 28→const extractBearerToken = (authHeader = "") => {
 29→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 30→    if (!trimmed) return "";
 31→
 32→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 33→    if (bearerMatch?.[1]) {
 34→        return bearerMatch[1].trim();
 35→    }
 36→
 37→    return trimmed;
 38→};
